1	<%*
2	// =============================================
3	// 修复剪藏笔记中代码块内的多余转义符号
4	// 使用方法：在任意笔记中运行 Templater 插入此模板
5	// =============================================
6	
7	const content = tp.file.content;
8	const lines = content.split("\n");
9	const result = [];
10	let inCodeBlock = false;
11	let fixCount = 0;
12	
13	// 只匹配 _ # * [ ] 这几个剪藏工具常转义的字符
14	const codeEscapeRe = /\\([_*#\[\]])/g;
15	// 有序列表：1\. 2\. 等
16	const orderedListRe = /(\d+)\\\./g;
17	
18	for (const line of lines) {
19	    if (line.trimStart().startsWith("```") || line.trimStart().startsWith("~~~")) {
20	        inCodeBlock = !inCodeBlock;
21	        result.push(line);
22	        continue;
23	    }
24	
25	    if (inCodeBlock) {
26	        const before = line;
27	        let cleaned = line.replace(codeEscapeRe, "$1");
28	        cleaned = cleaned.replace(orderedListRe, "$1.");
29	        if (cleaned !== before) fixCount++;
30	        result.push(cleaned);
31	    } else {
32	        result.push(line);
33	    }
34	}
35	
36	const cleaned = result.join("\n");
37	if (cleaned !== content) {
38	    await app.vault.modify(tp.file.find_tfile(tp.file.path), cleaned);
39	    tR += `✅ 修复完成，共修正 ${fixCount} 行`;
40	} else {
41	    tR += "✅ 未发现需要修复的转义";
42	}
43	%>
44
